+    [Parameter]
+    public EventCallback<Order> OnOrderPlaced { get; set; }
+
+    private readonly Order _order = new();
+    private WizardStep _step = WizardStep.Shipping;
+
+    private void HandleShippingComplete()
+    {
+        _step = WizardStep.Payment;
+    }
+
+    private void HandleBackToShipping()
+    {
+        _step = WizardStep.Shipping;
+    }
+
+    private async Task HandlePlaceOrder()
+    {
+        await OnOrderPlaced.InvokeAsync(_order);
+    }
+
+    private enum WizardStep { Shipping, Payment }
+}
